    DayName         VARCHAR(10) NOT NULL,
    WeekOfYear      TINYINT     NOT NULL,
    MonthNumber     TINYINT     NOT NULL,
    MonthName       VARCHAR(10) NOT NULL,
    QuarterNumber   TINYINT     NOT NULL,
    YearNumber      SMALLINT    NOT NULL,
    IsWeekend       BIT         NOT NULL
);*/

